// Script Continued Below
// 2.8.3 | 2023-06-21 | raj | DFCT0012026 - With Organizational Privacy turned On ~ GHA user in a Private Structure when adding New Sub OU>Organizational Privacy should NOT set Organizational Unit is Open
// 2.8.3 | 2023-06-20 | raj | DFCT0012030 - With Organizational Privacy turned On ~ GHA user in a Private Structure cannot add Sub OU. (It should be allowed) 
// 2.8.3 | 2023-06-20 | raj | DFCT0012031 - With Organizational Privacy turned On ~ GHA user in a Private Structure cannot Top Organizational Unit. (It should be allowed) 
// 2.8.x | 2023-05-07 | raj | DFCT0011813 - Set the Organizational Privacy to "Organization is Open", on change the "Set as External OU" is disabled. This SHOULD NOT be disabled. 
// 2.8.x  | 2023-05-05 - raj -  DFCT0011831 - Set the Organizational Privacy to "Organization is  Private", and "Set as External OU"  is editable by the platform admin 
// 2.8.x  | 2023-05-01 - raj -  DFCT0011799 - TBD - System Setting: Turn off Organizational Privacy > 
// 2.8.x  | 2023-04-30 - raj -  STRY0139319 - Removed the toast warning, and just disabled fields that can't be changed
// 2.8    | 2022-02-13 - raj -  STRY0117523 - Org Hierarchy- Office Schedule Override- Add System Settings to turn on/off feature
// 2.8 | 2022-07-06 | raj | STRY0116785 - ICE- Confirmation Modal: Updating OU Abbreviation updates Tasker Number 
// 2.8 | 2022-08-03 | raj | DFCT0011150 - Under the Deactivated OU  Should NOT be allowed to create an ACTIVE OU
// 2.8 | 2022-08-14 | raj | STRY0127037 - (MVP) Org Hierarchy- Schedule Override messaging "You don't have permissions"
(function executeRule(current, previous /*null when async*/) {
	// DFCT0011831
	g_scratchpad.isExternal = current.getDisplayValue("u_external_flag")==true || current.getDisplayValue("u_external_flag")=="true";

	// DFCT0011831
	g_scratchpad.organizationalPrivacy = current.getValue("u_organizational_privacy");

	var tsss = new tasking_System_Settings_Scripts();
	// DFCT0011799 - this should move into system settings get in a future release, put here for lowest impact in hotfix
	g_scratchpad.organizational_privacy_on = gs.getProperty("x_153465_discovert.organizational _privacy_options")=="On";

	// STRY0139319
	g_scratchpad.isTopOU = current.getDisplayValue("parent") == '' || current.getDisplayValue("parent") == null;

	// STRY0116785 - put the office abbreviation in the scratch pad
	g_scratchpad.office_abbreviation = current.getDisplayValue("office_abbreviation");

	// STRY0117523
	g_scratchpad.enable_office_schedule_override = tsss.getEnableOfficeScheduleOverideValue();

	// STRY0127037
	if(g_scratchpad.enable_office_schedule_override){
		var gr_schedule_override = new GlideRecord("cmn_schedule");
		g_scratchpad.canReadSchedule = gr_schedule_override.canRead();
	}

	// STRY0111887
	g_scratchpad.permissiveOUTasking = gs.getProperty('x_153465_discovert.PermissiveOUTaskingOptions'); 
	// if current record is new, and the parent is set, set the OU Level of this item to the parent + 1
	if(current.isNewRecord()){
		if (current.parent != ''){
			current.office_level = current.parent.office_level + 1;
			current.u_external_flag = current.parent.u_external_flag;

			// DFCT0012030 - DFCT0012031
			current.u_organizational_privacy = current.parent.u_organizational_privacy;

			// DFCT0011150
			current.active = current.parent.active;
			// DFCT0012026
			current.u_top_ou = current.parent.u_top_ou;
			g_scratchpad.OUHA_responsible = new OrganizationalScripts().getOUHA_responsible(current.getValue("parent"));
		} else{
			current.office_level = 1;
		}
		// STRY0111887
		if(g_scratchpad.permissiveOUTasking=='Allow Permissive OUs (Default checked for new OUs)'){
			current.u_ou_is_permissive = true;
		}
	// DFCT0012026
	} else {
		// STRY0059849 - OU Roles - OU Hierarchy Administrator
		g_scratchpad.OUHA_responsible = new OrganizationalScripts().getOUHA_responsible(current.getUniqueValue());
	}

	g_scratchpad.maxSortOrder = 0;
	// set the maximum value to display in the routes dropdown
	var gaGetMaxSortOrder;
	if (!current.parent.nil()){
		gaGetMaxSortOrder = new GlideAggregate('x_153465_discovert_discover_office_hierarchy');
		gaGetMaxSortOrder.addQuery('parent', current.parent);
		gaGetMaxSortOrder.addAggregate('MAX', 'level_order');
		gaGetMaxSortOrder.groupBy('parent');
		gaGetMaxSortOrder.query();
		if(gaGetMaxSortOrder.next()){
			g_scratchpad.maxSortOrder = gaGetMaxSortOrder.getAggregate('MAX', 'level_order');
			if(g_scratchpad.maxSortOrder == ''){
				g_scratchpad.maxSortOrder = 0;
			}
		}
	}
	// save current value to set back in form after reloading option list
	g_scratchpad.currentSortOrderValue = current.level_order;
})(current, previous);
